export function getConstantById(id: string): MathConstant | undefined {
  return NUMBER_BANK.find(c => c.id === id);
}

export function getDigitsOnly(constant: { digits: string }): string {
  return constant.digits.replace(/[^0-9]/g, "");
}

export function chunkDigits(digits: string, chunkSize: number = 5): string[] {
  const chunks: string[] = [];
  for (let i = 0; i < digits.length; i += chunkSize) {
    chunks.push(digits.slice(i, i + chunkSize));
  }
  return chunks;
}

export function digitToMajorSystem(digit: string): string[] {
  return MAJOR_SYSTEM[digit] || [];
}
